import { useState, useEffect, useMemo, useCallback } from "react";
import { useDataProvider, type RaRecord } from "react-admin";
import { logger } from "@/lib/logger";

interface DateRange {
  start: Date | null;
  end: Date | null;
}

interface UseReportDataOptions {
  /** Date range for filtering records */
  dateRange?: DateRange;
  /** Filter by sales rep ID */
  salesRepId?: string | null;
  /** Additional filters to merge with date/rep filters */
  additionalFilters?: Record<string, unknown>;
  /** Field to use for date filtering (default: "created_at") */
  dateField?: string;
  /** When provided with salesRepId, uses $or filter for primary + secondary fields */
  secondarySalesSource?: string;
}

interface UseReportDataResult<T> {
  /** Fetched data array */
  data: T[];
  /** Loading state */
  isLoading: boolean;
  /** Error if request failed (fail-fast, no retry) */
  error: Error | null;
  /** Trigger a refetch */
  refetch: () => void;
  /** True when total records exceed the pagination limit (1000) */
  isTruncated: boolean;
  /** Total record count from the data provider response */
  total: number;
}

/**
 * Custom hook for fetching report data through React Admin's data provider.
 *
 * Addresses audit finding A1: Centralizes data access instead of direct useGetList calls.
 * This ensures all report data flows through unifiedDataProvider for consistent
 * validation, error handling, and soft-delete filtering.
 *
 * Engineering Constitution Alignment:
 * - Single Entry Point: Uses useDataProvider (not direct Supabase)
 * - Fail-Fast: Errors surface immediately, no retry logic
 * - Type Safety: Generic constraint extends RaRecord
 *
 * @example
 * ```tsx
 * const { data, isLoading, error } = useReportData<Opportunity>("opportunities", {
 *   dateRange: { start: startDate, end: endDate },
 *   salesRepId: selectedRepId,
 *   additionalFilters: { "deleted_at@is": null },
 * });
 * ```
 */
export function useReportData<T extends RaRecord>(
  resource: string,
  options: UseReportDataOptions = {}
): UseReportDataResult<T> {
  const dataProvider = useDataProvider();
  const [data, setData] = useState<T[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);
  const [refetchTrigger, setRefetchTrigger] = useState(0);
  const [isTruncated, setIsTruncated] = useState(false);
  const [total, setTotal] = useState(0);

  const {
    dateRange,
    salesRepId,
    additionalFilters,
    dateField = "created_at",
    secondarySalesSource,
  } = options;

  // CRITICAL: Extract primitive values to prevent render loops
  // Objects (dateRange, additionalFilters) compared by reference cause infinite loops
  // when parent component creates new object references on each render
  const dateStartStr = dateRange?.start?.toISOString() ?? null;
  const dateEndStr = dateRange?.end?.toISOString() ?? null;
  // Memoize filter object using primitive dependencies only
  const filter = useMemo(() => {
    const baseFilter: Record<string, unknown> = additionalFilters ? { ...additionalFilters } : {};

    if (dateStartStr) {
      baseFilter[`${dateField}@gte`] = dateStartStr;
    }
    if (dateEndStr) {
      baseFilter[`${dateField}@lte`] = dateEndStr;
    }
    if (salesRepId) {
      if (secondarySalesSource) {
        baseFilter.$or = [{ sales_id: salesRepId }, { [secondarySalesSource]: salesRepId }];
      } else {
        baseFilter.sales_id = salesRepId;
      }
    }

    return baseFilter;
  }, [dateStartStr, dateEndStr, salesRepId, dateField, additionalFilters, secondarySalesSource]);

  useEffect(() => {
    let cancelled = false;
    setIsLoading(true);
    setError(null);

    dataProvider
      .getList<T>(resource, {
        /*
         * Large pagination limit for report aggregation (PERF-001).
         *
         * Rationale: Reports require complete datasets for:
         * - Grouping (by principal, rep, activity type)
         * - Calculating totals, averages, percentages
         * - Building charts with full data visibility
         * - CSV exports with all records
         *
         * Current scale: 6 reps, 9 principals, ~500 opportunities - within limit.
         * Limit: 1000 records (reduced from 10000 to prevent timeout issues).
         *
         * Migration path when data exceeds 1000 records:
         * 1. Implement Edge Function for server-side aggregation
         * 2. Move to cursor-based pagination with streaming
         * 3. Use materialized views for pre-computed metrics
         *
         * Performance monitoring:
         * - If queries exceed 2 seconds, migrate to server-side aggregation
         * - If data exceeds 1000 records, warning logged to console
         */
        pagination: { page: 1, perPage: 1000 },
        sort: { field: "id", order: "DESC" },
        filter,
      })
      .then((result) => {
        if (!cancelled) {
          if (result.data.length >= 1000) {
            logger.warn(
              `${resource}: Retrieved ${result.data.length} records (at pagination limit). Data may be truncated.`,
              { feature: "useReportData", resource }
            );
          }
          setData(result.data);
          setTotal(result.total ?? result.data.length);
          setIsTruncated((result.total ?? result.data.length) > 1000);
          setIsLoading(false);
        }
      })
      .catch((err: Error) => {
        if (!cancelled) {
          setError(err);
          setIsLoading(false);
          logger.error(`Failed to fetch ${resource}`, err, { feature: "useReportData", resource });
        }
      });

    return () => {
      cancelled = true;
    };
  }, [dataProvider, resource, filter, refetchTrigger]);

  const refetch = useCallback(() => {
    setRefetchTrigger((n) => n + 1);
  }, []);

  return { data, isLoading, error, refetch, isTruncated, total };
}
